function openAssignmentModal(id, viewOnly = false) {
    const modal = document.getElementById('assignmentModal');
    const titleInput = document.getElementById('assignment-title');
    titleInput.value = '';
    titleInput.classList.remove('invalid');
    document.getElementById('assignment-desc').value = '';
    document.getElementById('assignment-class').value = 'm1';
    document.getElementById('assignment-maxpoints').value = 10;
    document.getElementById('assignment-publish-now').checked = true;
    document.getElementById('assignment-publish-group').style.display = 'block';
    document.getElementById('assignment-status-group').style.display = 'none';
    document.getElementById('assignment-status').value = 'publish';
    modal.dataset.editId = '';
    document.getElementById('assignmentModalTitle').innerText = 'มอบหมายงานใหม่';
    document.getElementById('assignment-title').readOnly = false;
    document.getElementById('assignment-desc').readOnly = false;
    document.getElementById('assignment-class').disabled = false;
    document.getElementById('assignment-maxpoints').disabled = false;
    document.getElementById('assignment-status').disabled = false;

    currentAssignmentViewOnly = !!viewOnly;
    currentAttachments = [];

    const uploadZone = document.getElementById('assignment-upload-zone');
    if (uploadZone) {
        if (viewOnly) {
            uploadZone.style.pointerEvents = 'none';
            uploadZone.style.opacity = '0.6';
        } else {
            uploadZone.style.pointerEvents = 'auto';
            uploadZone.style.opacity = '1';
        }
    }

    if (id) {
        const arr = getAssignments();
        const item = arr.find(a=>a.id===id);
        if (item) {
            const titleInput = document.getElementById('assignment-title');
            titleInput.value = item.title || '';
            titleInput.classList.remove('invalid');
            document.getElementById('assignment-desc').value = item.description || '';
            document.getElementById('assignment-class').value = item.class || 'm3';
            document.getElementById('assignment-maxpoints').value = item.maxPoints || 10;
            const normalizedStatus = item.status === 'overdue' ? 'late' : item.status || (item.visible === false ? 'draft' : (item.openForSubmissions === false ? 'closed' : 'publish'));
            document.getElementById('assignment-status').value = normalizedStatus;
            document.getElementById('assignment-publish-group').style.display = 'none';
            document.getElementById('assignment-status-group').style.display = 'block';
            modal.dataset.editId = id;
            document.getElementById('assignmentModalTitle').innerText = viewOnly ? 'ดูมอบหมายงาน' : 'แก้ไขมอบหมายงาน';
            // Toggle readonly when viewing
            document.getElementById('assignment-title').readOnly = !!viewOnly;
            document.getElementById('assignment-desc').readOnly = !!viewOnly;
            document.getElementById('assignment-class').disabled = !!viewOnly;
            document.getElementById('assignment-maxpoints').disabled = !!viewOnly;
            document.getElementById('assignment-status').disabled = !!viewOnly;

            currentAttachments = [...(item.attachments || [])];
        }
    }

    renderModalAttachments();
    modal.style.display = 'flex';
}

